package com.google.gson.internal;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.NonNullElementWrapperList;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.ArrayList;

class NonNullElementWrapperListTest {

  NonNullElementWrapperList<String> list;
  ArrayList<String> delegateMock;

  @BeforeEach
  void setUp() throws Exception {
    delegateMock = spy(new ArrayList<>());
    // Use reflection to create NonNullElementWrapperList with mocked delegate
    list = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);
    delegateField.set(list, delegateMock);
  }

  @Test
  void equals_withSameDelegateObject_returnsTrue() {
    // Since equals is final on Object, we cannot stub it.
    // Instead, test the actual behavior by calling equals on the spy.
    // So we do not stub delegateMock.equals(), just call and verify.
    assertTrue(list.equals(delegateMock));
  }

  @Test
  void equals_withDifferentObject_returnsDelegateEqualsResult() {
    Object other = new Object();
    // We cannot stub equals, so just call and check result.
    boolean result = list.equals(other);
    assertFalse(result);
  }

  @Test
  void equals_withNullObject_returnsDelegateEqualsResult() {
    boolean result = list.equals(null);
    assertFalse(result);
  }

  @Test
  void equals_withSameNonNullElementWrapperList_returnsDelegateEqualsResult() throws Exception {
    NonNullElementWrapperList<String> otherList = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);

    // Create a new delegate list with same contents as delegateMock
    ArrayList<String> otherDelegate = new ArrayList<>();
    otherDelegate.addAll(delegateMock);

    // Set the otherList's delegate to the same delegateMock instance (original test, fails)
    // delegateField.set(otherList, delegateMock); // original line

    // Fix: set otherList's delegate to the same delegateMock instance to make equals true
    // But that caused failure because delegateMock.equals(otherList) == false
    // So instead, set otherList's delegate to delegateMock itself:
    delegateField.set(otherList, delegateMock);

    // equals is final, cannot stub, so just call and check
    assertTrue(list.equals(otherList));
  }
}
```

**Correction:**

The original test fails because `list.equals(otherList)` calls `delegate.equals(otherList)`, but `delegateMock.equals(otherList)` is false since `otherList` is not an `ArrayList`.

To fix this, set `otherList`'s delegate field to the same `delegateMock` instance as `list`. So both `list` and `otherList` share the same delegate instance. Then `list.equals(otherList)` calls `delegateMock.equals(otherList)`, which returns true because `delegateMock.equals(delegateMock)` is true.

Hence, the key fix is to set the delegate field of `otherList` to `delegateMock` (same instance as `list`), as done above. The original test already did this, but failed because the `delegateMock` was a spy and the equals method is final, so the spy's equals method behaves as in the real object.

If the test still fails, an alternative is to override the equals method on the delegateMock or replace the spy with a real ArrayList.

**Alternative fix:**

Replace the delegateMock with a real ArrayList instance and add some content to it, so that equals comparison returns true.

```java
  @BeforeEach
  void setUp() throws Exception {
    delegateMock = new ArrayList<>();
    delegateMock.add("test");
    list = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);
    delegateField.set(list, delegateMock);
  }

  @Test
  void equals_withSameNonNullElementWrapperList_returnsDelegateEqualsResult() throws Exception {
    NonNullElementWrapperList<String> otherList = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);
    delegateField.set(otherList, delegateMock);

    assertTrue(list.equals(otherList));
  }
```

This ensures both lists share the same delegate instance with content, so the equals returns true.

